#include <iostream>
#include <fstream>
#include <string>
#include <cassert>

// This program reads a text file and counts the occurrences of a specific word.
// Usage: count_word_occurrences("example.txt", "word");

int count_word_occurrences(const std::string& filename, const std::string& word) {
    std::ifstream file(filename);
    assert(file.is_open() && "File could not be opened");

    std::string line;
    int count = 0;
    while (getline(file, line)) {
        std::string::size_type pos = 0;
        while ((pos = line.find(word, pos)) != std::string::npos) {
            if ((pos == 0 || !std::isalpha(line[pos - 1])) &&
                (pos + word.length() == line.length() || !std::isalpha(line[pos + word.length()]))) {
                count++;
            }
            pos += word.length();
        }
    }
    file.close();
    return count;
}

// Function to check if the word counting works correctly
void check_function() {
    int occurrences = count_word_occurrences("example.txt", "word");
    assert(occurrences == 5 && "The word count is incorrect");
    std::cout << "Test passed: The word 'word' appears " << occurrences << " times." << std::endl;
}

int main() {
    // Call the check function to verify the correctness of the word counting
    check_function();
    return 0;
}
